class Solution:
    def minSwaps(self, grid):
        import itertools
        n = len(grid)
        def trailing_zeros(row):
            z = 0
            for v in reversed(row):
                if v == 0:
                    z += 1
                else:
                    break
            return z
        best = None
        for perm in itertools.permutations(range(n)):
            valid = all(trailing_zeros(grid[perm[i]]) >= n - i - 1 for i in range(n))
            if not valid:
                continue
            a = list(perm)
            swaps = 0
            for i in range(n):
                if a[i] != i:
                    j = a.index(i)
                    while j > i:
                        a[j], a[j - 1] = a[j - 1], a[j]
                        j -= 1
                        swaps += 1
            if best is None or swaps < best:
                best = swaps
        return best if best is not None else -1

