class Solution:
    def minSwaps(self, grid):
        n = len(grid)
        trailing = []
        for row in grid:
            z = 0
            for v in reversed(row):
                if v == 0:
                    z += 1
                else:
                    break
            trailing.append(z)
        ans = 0
        for i in range(n):
            need = n - i - 1
            if trailing[i] >= need:
                continue
            j = i + 1
            while j < n and trailing[j] < need:
                j += 1
            if j == n:
                return -1
            row = trailing.pop(j)
            trailing.insert(i, row)
            ans += j - i
        return ans

