var minSwaps = function(grid) {
    const n = grid.length;
    const trailing = grid.map(row => {
        let z = 0;
        for (let i = row.length - 1; i >= 0; i--) {
            if (row[i] === 0) z++; else break;
        }
        return z;
    });
    let ans = 0;
    for (let i = 0; i < n; i++) {
        const need = n - i - 1;
        if (trailing[i] >= need) continue;
        let j = i + 1;
        while (j < n && trailing[j] < need) j++;
        if (j === n) return -1;
        const [row] = trailing.splice(j, 1);
        trailing.splice(i, 0, row);
        ans += j - i;
    }
    return ans;
};
